  | "invalid_format"
  | "disposable"
  | "undeliverable";

export type ValidationResult =
  | { valid: true }
  | { valid: false; reason: ValidationFailureReason };

const TRUSTED_DOMAINS = new Set([
  "gmail.com",
  "googlemail.com",
  "outlook.com",
  "hotmail.com",
  "live.com",
  "yahoo.com",
  "icloud.com",
  "me.com",
