  "proton.me",
  "fastmail.com",
  "hey.com",
  "aol.com",
  "zoho.com",
  "yandex.com",
  "mail.com",
]);

const AbstractApiResponse = z.object({
  deliverability: z.enum(["DELIVERABLE", "UNDELIVERABLE", "RISKY", "UNKNOWN"]),
});

export function isDisposableEmail(email: string): boolean {
  const domain = email.split("@")[1]?.toLowerCase();
  if (!domain) {
